476: // watchWithResync runs watch with startResync in the background.
477: func (r *Reflector) watchWithResync(ctx context.Context, w watch.Interface) error {
478: 	resyncerrc := make(chan error, 1)
479: 	cancelCtx, cancel := context.WithCancel(ctx)
480: 	// Waiting for completion of the goroutine is relevant for race detector.
481: 	// Without this, there is a race between "this function returns + code
482: 	// waiting for it" and "goroutine does something".
483: 	var wg wait.Group
484: 	defer func() {
485: 		cancel()
486: 		wg.Wait()
487: 	}()
488: 	wg.Start(func() {
489: 		r.startResync(cancelCtx, resyncerrc)
490: 	})
491: 	return r.watch(ctx, w, resyncerrc)
492: }
